package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// TestNewPolicyAuditLogger tests the creation of a PolicyAuditLogger.
func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.DebugLevel, logger.level)
	require.NotNil(t, logger.logger)
}

// TestNewPolicyAuditLoggerWithLogger tests the creation of a PolicyAuditLogger with custom logger.
func TestNewPolicyAuditLoggerWithLogger(t *testing.T) {
	customLogger := logrus.New()
	logger := NewPolicyAuditLoggerWithLogger(customLogger, logrus.InfoLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.InfoLevel, logger.level)
}

// TestLogDecision tests that LogDecision properly logs policy decisions.
func TestLogDecision(t *testing.T) {
	// Create a logger with a hook to capture log entries
	logrusLogger := logrus.New()
	logrusLogger.SetLevel(logrus.DebugLevel)

	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.InfoLevel)
	require.NotNil(t, auditLogger)

	// Test logging a policy decision
	testID := identity.NumericIdentity(100)
	testPolicy := "test-policy"
	testVerdict := "allow"
	testReason := "traffic matches ingress rule"

	auditLogger.LogDecision(testID, testPolicy, testVerdict, testReason)
	// Note: Without a hook, we're just verifying the function executes without panic
}

// TestLogDecisionThreadSafety tests that LogDecision is thread-safe.
func TestLogDecisionThreadSafety(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.DebugLevel)

	done := make(chan bool)

	// Launch multiple goroutines to test thread safety
	for i := 0; i < 10; i++ {
		go func(idx int) {
			id := identity.NumericIdentity(idx)
			auditLogger.LogDecision(id, "policy", "allow", "test")
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}
}

// TestLogEvaluation tests that LogEvaluation properly logs policy evaluations.
func TestLogEvaluation(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.InfoLevel)

	// Create a simple evaluation result
	result := &PolicyEvaluationResult{
		PolicyKey: "test-policy-key",
		Verdict:   "allow",
		Reason:    "matches ingress rule",
	}

	// Create a context
	ctx := context.Background()

	// Test logging an evaluation (with nil selector cache)
	auditLogger.LogEvaluation(ctx, "test-policy-key", nil, result)
}

// TestLogEvaluationWithDetails tests LogEvaluation with additional details.
func TestLogEvaluationWithDetails(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.DebugLevel)

	// Create an evaluation result with details
	details := map[string]interface{}{
		"rule_index": 5,
		"l4_policy":  "TCP/443",
	}

	result := &PolicyEvaluationResult{
		PolicyKey: "test-policy-key",
		Verdict:   "deny",
		Reason:    "no matching rules",
		Details:   details,
	}

	ctx := context.Background()
	auditLogger.LogEvaluation(ctx, "test-policy-key", nil, result)
}

// TestLogEvaluationWithContext tests LogEvaluation with a context containing a request ID.
func TestLogEvaluationWithContext(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.InfoLevel)

	result := &PolicyEvaluationResult{
		PolicyKey: "test-policy-key",
		Verdict:   "allow",
	}

